using System;
using Microsoft.Build.Logging.StructuredLogger;

var binlogPath = args[0];
var build = BinaryLog.ReadBuild(binlogPath);

Console.WriteLine("=== BUILD RESULT: " + (build.Succeeded ? "SUCCEEDED" : "FAILED") + " ===");
Console.WriteLine();

// Get unique build invocations per project with their targets
Console.WriteLine("=== PROJECT BUILD TARGETS ===");
build.VisitAllChildren<Project>(project => {
    var targets = project.GetNearestParent<Build>() != null ? "solution-level" : "direct";
    var hasErrors = false;
    project.VisitAllChildren<Error>(e => hasErrors = true);
    if (hasErrors || project.Name.Contains("Api") || project.Name.Contains("Services")) {
        Console.WriteLine($"  {project.Name} [TargetFramework={project.TargetFramework}] HasErrors={hasErrors}");
        // Check if CoreCompile target ran
        project.VisitAllChildren<Target>(t => {
            if (t.Name == "CoreCompile" || t.Name == "Build" || t.Name == "ResolveProjectReferences") {
                Console.WriteLine($"    Target: {t.Name}");
            }
        });
    }
});

Console.WriteLine();
Console.WriteLine("=== DETAILED ERRORS ===");
build.VisitAllChildren<Error>(error => {
    Console.WriteLine($"  [{error.ProjectFile}]");
    Console.WriteLine($"    {error.File}({error.LineNumber},{error.ColumnNumber}): error {error.Code}: {error.Text}");
    Console.WriteLine();
});
EOF
